7	
8	
9	#include <njs_main.h>
10	
11	
12	static njs_declaration_t *njs_variable_scope_function_add(njs_parser_t *parser,
13	    njs_parser_scope_t *scope);
14	static njs_parser_scope_t *njs_variable_scope_find(njs_parser_t *parser,
15	     njs_parser_scope_t *scope, uintptr_t atom_id, njs_variable_type_t type);
16	static njs_variable_t *njs_variable_alloc(njs_vm_t *vm, uintptr_t atom_id,
17	    njs_variable_type_t type);
18	
19	
20	njs_variable_t *
21	njs_variable_add(njs_parser_t *parser, njs_parser_scope_t *scope,
22	    uintptr_t atom_id, njs_variable_type_t type)
23	{
24	    njs_parser_scope_t  *root;
25	
26	    root = njs_variable_scope_find(parser, scope, atom_id, type);
27	    if (njs_slow_path(root == NULL)) {
28	        njs_parser_ref_error(parser, "scope not found");
29	        return NULL;
30	    }
31	
32	    return njs_variable_scope_add(parser, root, scope, atom_id, type,
33	                                  NJS_INDEX_NONE);
34	}
35	
36	
37	njs_variable_t *
38	njs_variable_function_add(njs_parser_t *parser, njs_parser_scope_t *scope,
39	    uintptr_t atom_id)
40	{
41	    njs_bool_t             ctor;
42	    njs_variable_t         *var;
43	    njs_declaration_t      *declr;
44	    njs_parser_scope_t     *root;
45	    njs_function_lambda_t  *lambda;
46	
47	    root = njs_variable_scope_find(parser, scope, atom_id,
48	                                   NJS_VARIABLE_FUNCTION);
49	    if (njs_slow_path(root == NULL)) {
50	        njs_parser_ref_error(parser, "scope not found");
51	        return NULL;
52	    }
53	
54	    var = njs_variable_scope_add(parser, root, scope, atom_id,
55	                                 NJS_VARIABLE_FUNCTION, NJS_INDEX_ERROR);
56	    if (njs_slow_path(var == NULL)) {
57	        return NULL;
58	    }
59	
60	    root = njs_function_scope(scope);
61	    if (njs_slow_path(root == NULL)) {
62	        return NULL;
63	    }
64	
65	    ctor = parser->node->token_type != NJS_TOKEN_ASYNC_FUNCTION_DECLARATION;
66	
67	    lambda = njs_function_lambda_alloc(parser->vm, ctor);
68	    if (lambda == NULL) {
69	        return NULL;
70	    }
71	
72	    njs_set_invalid(&var->value);
73	    var->value.data.u.lambda = lambda;
74	
75	    declr = njs_variable_scope_function_add(parser, root);
76	    if (njs_slow_path(declr == NULL)) {
77	        return NULL;
78	    }
79	
80	    var->index = njs_scope_index(root->type, root->items, NJS_LEVEL_LOCAL,
81	                                 NJS_VARIABLE_FUNCTION);
82	
83	    declr->lambda = lambda;
84	    declr->async = !ctor;
85	    declr->index = var->index;
86	
87	    root->items++;
88	
89	    var->type = NJS_VARIABLE_FUNCTION;
90	
91	    return var;
92	}
93	
94	
95	static njs_declaration_t *
96	njs_variable_scope_function_add(njs_parser_t *parser, njs_parser_scope_t *scope)
97	{
98	    if (scope->declarations == NULL) {
99	        scope->declarations = njs_arr_create(parser->vm->mem_pool, 1,
100	                                             sizeof(njs_declaration_t));
101	        if (njs_slow_path(scope->declarations == NULL)) {
102	            return NULL;
103	        }
104	    }
105	
106	    return njs_arr_add(scope->declarations);
107	}
108	
109	
110	static njs_parser_scope_t *
111	njs_variable_scope(njs_parser_scope_t *scope, uintptr_t atom_id,
112	    njs_variable_t **retvar, njs_variable_type_t type)
113	{
114	    njs_variable_t       *var;
115	    njs_rbtree_node_t    *node;
116	    njs_variable_node_t  var_node;
117	
118	    *retvar = NULL;
119	
120	    var_node.key = atom_id;
121	
122	    do {
123	        node = njs_rbtree_find(&scope->variables, &var_node.node);
124	
125	        if (node != NULL) {
126	            var = ((njs_variable_node_t *) node)->variable;
127	
128	            if (var->type != NJS_VARIABLE_CATCH || type != NJS_VARIABLE_VAR) {
129	                *retvar = var;
130	                return scope;
131	            }
132	        }
133	
134	        if (scope->type == NJS_SCOPE_GLOBAL
135	            || scope->type == NJS_SCOPE_FUNCTION)
136	        {
137	            return scope;
138	        }
139	
140	        scope = scope->parent;
141	
142	    } while (scope != NULL);
143	
144	    return NULL;
145	}
146	
147	
148	static njs_parser_scope_t *
149	njs_variable_scope_find(njs_parser_t *parser, njs_parser_scope_t *scope,
150	     uintptr_t atom_id, njs_variable_type_t type)
151	{
152	    njs_str_t           entry;
153	    njs_bool_t          module;
154	    njs_variable_t      *var;
155	    njs_parser_scope_t  *root;
156	
157	    root = njs_variable_scope(scope, atom_id, &var, type);
158	    if (njs_slow_path(root == NULL)) {
159	        return NULL;
160	    }
161	
162	    switch (type) {
163	    case NJS_VARIABLE_CONST:
164	    case NJS_VARIABLE_LET:
165	        if (scope->type == NJS_SCOPE_GLOBAL
166	            && atom_id == NJS_ATOM_STRING_undefined)
167	        {
168	            goto failed;
169	        }
170	
171	        if (root != scope) {
172	            return scope;
173	        }
174	
175	        if (var != NULL && var->scope == root) {
176	            if (var->self) {
177	                return scope;
178	            }
179	
180	            goto failed;
181	        }
182	
183	        return scope;
184	
185	    case NJS_VARIABLE_VAR:
186	    case NJS_VARIABLE_FUNCTION:
187	        break;
188	
189	    default:
190	        return scope;
191	    }
192	
193	    if (type == NJS_VARIABLE_FUNCTION) {
194	        root = scope;
195	    }
196	
197	    if (var == NULL) {
198	        return root;
199	    }
200	
201	    if (var->type == NJS_VARIABLE_LET || var->type == NJS_VARIABLE_CONST) {
202	        goto failed;
203	    }
204	
205	    if (var->original->type == NJS_SCOPE_BLOCK) {
206	        if (type == NJS_VARIABLE_FUNCTION
207	            || var->type == NJS_VARIABLE_FUNCTION)
208	        {
209	            if (var->original == root) {
210	                goto failed;
211	            }
212	        }
213	    }
214	
215	    if (type != NJS_VARIABLE_FUNCTION
216	        && var->type != NJS_VARIABLE_FUNCTION)
217	    {
218	        return var->scope;
219	    }
220	
221	    if (root != scope) {
222	        return root;
223	    }
224	
225	    if (scope->parent == NULL) {
226	        module = parser->vm->options.module || parser->module;
227	
228	        if (module) {
229	            if (type == NJS_VARIABLE_FUNCTION
230	                || var->type == NJS_VARIABLE_FUNCTION)
231	            {
232	                goto failed;
233	            }
234	        }
235	
236	    }
237	
238	    return root;
239	
240	failed:
241	
242	    njs_atom_string_get(parser->vm, atom_id, &entry);
243	
244	    njs_parser_syntax_error(parser, "\"%V\" has already been declared", &entry);
245	    return NULL;
246	}
247	
248	
249	njs_variable_t *
250	njs_variable_scope_add(njs_parser_t *parser, njs_parser_scope_t *scope,
251	    njs_parser_scope_t *original, uintptr_t atom_id,
252	    njs_variable_type_t type, njs_index_t index)
253	{
254	    njs_variable_t       *var;
255	    njs_rbtree_node_t    *node;
256	    njs_parser_scope_t   *root;
257	    njs_variable_node_t  var_node, *var_node_new;
258	
259	    var_node.key = atom_id;
260	
261	    node = njs_rbtree_find(&scope->variables, &var_node.node);
262	
263	    if (node != NULL) {
264	        return ((njs_variable_node_t *) node)->variable;
265	    }
266	
267	    var = njs_variable_alloc(parser->vm, atom_id, type);
268	    if (njs_slow_path(var == NULL)) {
269	        goto memory_error;
270	    }
271	
272	    var->scope = scope;
273	    var->index = index;
274	    var->original = original;
275	
276	    if (index == NJS_INDEX_NONE) {
277	        root = njs_function_scope(scope);
278	        if (njs_slow_path(root == NULL)) {
279	            return NULL;
280	        }
281	
282	        var->index = njs_scope_index(root->type, root->items, NJS_LEVEL_LOCAL,
283	                                     type);
284	        root->items++;
285	    }
286	
287	    var_node_new = njs_variable_node_alloc(parser->vm, var, atom_id);
288	    if (njs_slow_path(var_node_new == NULL)) {
289	        goto memory_error;
290	    }
291	
292	    njs_rbtree_insert(&scope->variables, &var_node_new->node);
293	
294	    return var;
295	
296	memory_error:
297	
298	    njs_memory_error(parser->vm);
299	
300	    return NULL;
301	}
