304	njs_variable_t *
305	njs_label_add(njs_vm_t *vm, njs_parser_scope_t *scope, uintptr_t atom_id)
306	{
307	    njs_variable_t       *label;
308	    njs_rbtree_node_t    *node;
309	    njs_variable_node_t  var_node, *var_node_new;
310	
311	    var_node.key = atom_id;
312	
313	    node = njs_rbtree_find(&scope->labels, &var_node.node);
314	
315	    if (node != NULL) {
316	        return ((njs_variable_node_t *) node)->variable;
317	    }
318	
319	    label = njs_variable_alloc(vm, atom_id, NJS_VARIABLE_CONST);
320	    if (njs_slow_path(label == NULL)) {
321	        goto memory_error;
322	    }
323	
324	    var_node_new = njs_variable_node_alloc(vm, label, atom_id);
325	    if (njs_slow_path(var_node_new == NULL)) {
326	        goto memory_error;
327	    }
328	
329	    njs_rbtree_insert(&scope->labels, &var_node_new->node);
330	
331	    return label;
