362	njs_bool_t
363	njs_variable_closure_test(njs_parser_scope_t *root, njs_parser_scope_t *scope)
364	{
365	    if (root == scope) {
366	        return 0;
367	    }
368	
369	    do {
370	        if (root->type == NJS_SCOPE_FUNCTION) {
371	            return 1;
372	        }
373	
374	        root = root->parent;
375	
376	    } while (root != scope);
377	
378	    return 0;
379	}
