382	njs_variable_t *
383	njs_variable_resolve(njs_vm_t *vm, njs_parser_node_t *node)
384	{
385	    njs_rbtree_node_t         *rb_node;
386	    njs_parser_scope_t        *scope;
387	    njs_variable_node_t       var_node;
388	    njs_variable_reference_t  *ref;
389	
390	    ref = &node->u.reference;
391	    scope = node->scope;
392	
393	    var_node.key = ref->atom_id;
394	
395	    do {
396	        rb_node = njs_rbtree_find(&scope->variables, &var_node.node);
397	
398	        if (rb_node != NULL) {
399	            return ((njs_variable_node_t *) rb_node)->variable;
400	        }
401	
402	        scope = scope->parent;
403	
404	    } while (scope != NULL);
405	
406	    return NULL;
407	}
408	
409	
410	static njs_index_t
411	njs_variable_closure(njs_vm_t *vm, njs_variable_t *var,
412	    njs_parser_scope_t *scope)
413	{
414	    njs_index_t               index, prev_index, *idx;
415	    njs_level_type_t          type;
416	    njs_rbtree_node_t         *rb_node;
417	    njs_parser_scope_t        **p;
418	    njs_parser_rbtree_node_t  *parse_node, ref_node;
419	#define NJS_VAR_MAX_DEPTH     32
420	    njs_parser_scope_t        *list[NJS_VAR_MAX_DEPTH];
421	
422	    ref_node.key = var->atom_id;
423	
424	    p = list;
425	
426	    do {
427	        if (njs_slow_path(p == &list[NJS_VAR_MAX_DEPTH - 1])) {
428	            njs_error(vm, "maximum depth of nested functions is reached");
429	            return NJS_INDEX_ERROR;
430	        }
431	
432	        if (scope->type == NJS_SCOPE_FUNCTION) {
433	            *p++ = scope;
434	        }
435	
436	        scope = scope->parent;
437	
438	    } while (scope != var->scope && scope->type != NJS_SCOPE_GLOBAL);
439	
440	    prev_index = var->index;
441	
442	    while (p != list) {
443	        p--;
444	
445	        scope = *p;
446	
447	        rb_node = njs_rbtree_find(&scope->references, &ref_node.node);
448	
449	        parse_node = ((njs_parser_rbtree_node_t *) rb_node);
450	
451	        type = NJS_LEVEL_LOCAL;
452	
453	        if (parse_node != NULL) {
454	            type = njs_scope_index_type(parse_node->index);
455	
456	            if (p != list && parse_node->index != 0) {
457	                prev_index = parse_node->index;
458	                continue;
459	            }
460	        }
461	
462	        if (type != NJS_LEVEL_CLOSURE) {
463	            /* Create new closure for scope. */
464	
465	            index = njs_scope_index(scope->type, scope->closures->items,
466	                                    NJS_LEVEL_CLOSURE, var->type);
467	            if (njs_slow_path(index == NJS_INDEX_ERROR)) {
468	                return NJS_INDEX_ERROR;
469	            }
470	
471	            idx = njs_arr_add(scope->closures);
472	            if (njs_slow_path(idx == NULL)) {
473	                return NJS_INDEX_ERROR;
474	            }
475	
476	            *idx = prev_index;
477	
478	            if (parse_node == NULL) {
479	                /* Create new reference for closure. */
480	
481	                parse_node = njs_mp_alloc(vm->mem_pool,
482	                                          sizeof(njs_parser_rbtree_node_t));
483	                if (njs_slow_path(parse_node == NULL)) {
484	                    return NJS_INDEX_ERROR;
485	                }
486	
487	                parse_node->key = var->atom_id;
488	
489	                njs_rbtree_insert(&scope->references, &parse_node->node);
490	            }
491	
492	            parse_node->index = index;
493	        }
494	
495	        prev_index = parse_node->index;
496	    }
497	
498	    return prev_index;
499	}
500	
501	
502	njs_variable_t *
503	njs_variable_reference(njs_vm_t *vm, njs_parser_node_t *node)
504	{
505	    njs_bool_t                closure;
506	    njs_rbtree_node_t         *rb_node;
507	    njs_parser_scope_t        *scope;
508	    njs_parser_rbtree_node_t  *parse_node, ref_node;
509	    njs_variable_reference_t  *ref;
510	
511	    ref = &node->u.reference;
512	    scope = node->scope;
513	
514	    if (ref->variable == NULL) {
515	        ref->variable = njs_variable_resolve(vm, node);
516	        if (njs_slow_path(ref->variable == NULL)) {
517	            ref->not_defined = 1;
518	
519	            return NULL;
520	        }
521	    }
522	
523	    closure = njs_variable_closure_test(node->scope, ref->variable->scope);
524	    ref->scope = node->scope;
525	
526	    ref_node.key = ref->atom_id;
527	
528	    rb_node = njs_rbtree_find(&scope->references, &ref_node.node);
529	    if (njs_slow_path(rb_node == NULL)) {
530	        return NULL;
531	    }
532	
533	    parse_node = ((njs_parser_rbtree_node_t *) rb_node);
534	
535	    if (parse_node->index != NJS_INDEX_NONE) {
536	        node->index = parse_node->index;
537	
538	        return ref->variable;
539	    }
540	
541	    if (!closure) {
542	        node->index = ref->variable->index;
543	
544	        return ref->variable;
545	    }
546	
547	    ref->variable->closure = closure;
548	
549	    node->index = njs_variable_closure(vm, ref->variable, scope);
550	    if (njs_slow_path(node->index == NJS_INDEX_ERROR)) {
551	        return NULL;
552	    }
553	
554	    return ref->variable;
555	}
556	
557	
558	njs_variable_t *
559	njs_label_find(njs_vm_t *vm, njs_parser_scope_t *scope, uintptr_t atom_id)
560	{
561	    njs_rbtree_node_t    *node;
562	    njs_variable_node_t  var_node;
563	
564	    var_node.key = atom_id;
565	
566	    do {
567	        node = njs_rbtree_find(&scope->labels, &var_node.node);
568	
569	        if (node != NULL) {
570	            return ((njs_variable_node_t *) node)->variable;
571	        }
572	
573	        scope = scope->parent;
574	
575	    } while (scope != NULL);
576	
577	    return NULL;
578	}
579	
580	
581	static njs_variable_t *
582	njs_variable_alloc(njs_vm_t *vm, uintptr_t atom_id, njs_variable_type_t type)
583	{
584	    njs_variable_t  *var;
585	
586	    var = njs_mp_zalloc(vm->mem_pool, sizeof(njs_variable_t));
587	    if (njs_slow_path(var == NULL)) {
588	        njs_memory_error(vm);
589	        return NULL;
590	    }
591	
592	    var->atom_id = atom_id;
593	    var->type = type;
594	
595	    return var;
596	}
597	
598	
599	njs_int_t
600	njs_name_copy(njs_vm_t *vm, njs_str_t *dst, const njs_str_t *src)
601	{
602	    dst->length = src->length;
603	
604	    dst->start = njs_mp_alloc(vm->mem_pool, src->length);
605	
606	    if (njs_fast_path(dst->start != NULL)) {
607	        (void) memcpy(dst->start, src->start, src->length);
608	
609	        return NJS_OK;
610	    }
611	
612	    njs_memory_error(vm);
613	
614	    return NJS_ERROR;
615	}
