    end = msg + NJS_MAX_ERROR_STR;

    p = njs_vsprintf(p, end, fmt, args);

    njs_error_new(vm, &error, njs_vm_proto(vm, type), msg, p - msg);

    if (!vm->options.quiet && file->length != 0) {
        njs_error_stack_set(vm, &error, file, line);
    }

    njs_vm_throw(vm, &error);
}

